from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent, complex sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present and trim whitespace."""
        return val.strip().strip('"').strip("'")

    # Helper to build a clause for a single triple
    def _clause(s: str, p: str, o: str) -> str:
        if p == "cityServed":
            return f"{s} serves the city of {o}"
        if p == "location":
            return f"{s} is located in {o}"
        if p == "country":
            return f"{s} is in {o}"
        if p == "isPartOf":
            return f"{s} is part of {o}"
        if p == "elevationAboveTheSeaLevel":
            return f"{s} lies at an elevation of {o} metres above sea level"
        if p == "elevationAboveTheSeaLevelInFeet":
            return f"{s} lies at an elevation of {o} feet above sea level"
        if p == "operatingOrganisation":
            return f"{s} is operated by {o}"
        if p == "runwaySurfaceType":
            return f"{s} has a runway surface of {o}"
        if p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway is {o} feet long"
        if p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway is {o} metres long"
        if p == "runwayName":
            return f"{s}'s runway is named {o}"
        if p == "runwayLength":
            return f"{s}'s runway length is {o}"
        # Additional airport‑specific predicates
        if p == "iataLocationIdentifier":
            return f"{s} has IATA code {o}"
        if p == "icaoLocationIdentifier":
            return f"{s} has ICAO code {o}"
        if p == "locationIdentifier":
            return f"{s} has location identifier {o}"
        if p == "owner":
            return f"{s} is owned by {o}"
        if p == "headquarter":
            return f"{s} has its headquarter at {o}"
        if p == "hubAirport":
            return f"{s} uses {o} as a hub airport"
        if p == "regionServed":
            return f"{s} serves the region of {o}"
        if p == "largestCity":
            return f"The largest city of {s} is {o}"
        if p == "capital":
            return f"The capital of {s} is {o}"
        if p == "language":
            return f"{s} uses {o} as its language"
        if p == "officialLanguage":
            return f"{s}'s official language is {o}"
        if p == "currency":
            return f"{s} uses the {o}"
        if p == "foundingYear":
            return f"{s} was founded in {o}"
        if p == "postalCode":
            return f"{s}'s postal code is {o}"
        if p == "areaCode":
            return f"{s}'s area code is {o}"
        if p == "ceremonialCounty":
            return f"{s} is in the ceremonial county of {o}"
        if p == "countySeat":
            return f"The county seat of {s} is {o}"
        if p == "chief":
            return f"The chief of {s} is {o}"
        # Fallback for any other predicate
        return f"{s} has {p} {o}"

    # Group objects by subject and predicate to allow merging (e.g., multiple cities served)
    from collections import defaultdict

    grouped = defaultdict(lambda: defaultdict(list))  # subject -> predicate -> [objects]
    for t in triples:
        subj = t.subject
        pred = t.predicate
        obj = _clean(t.object)
        grouped[subj][pred].append(obj)

    # Helper to render a subject block
    def _render_subject(subj: str, pred_map: dict) -> str:
        parts = []
        for pred, objs in pred_map.items():
            # Merge multiple objects for certain predicates
            if pred == "cityServed":
                city_list = ", ".join(objs[:-1]) + (" and " + objs[-1] if len(objs) > 1 else objs[0])
                parts.append(f"{subj} serves the city{'ies' if len(objs) > 1 else ''} of {city_list}")
                continue
            if pred.endswith("RunwayLengthFeet"):
                idx = pred.split("Runway")[0]
                length = ", ".join(objs[:-1]) + (" and " + objs[-1] if len(objs) > 1 else objs[0])
                parts.append(f"{subj}'s {idx.lower()} runway is {length} feet long")
                continue
            if pred.endswith("RunwayLengthMetre"):
                idx = pred.split("Runway")[0]
                length = ", ".join(objs[:-1]) + (" and " + objs[-1] if len(objs) > 1 else objs[0])
                parts.append(f"{subj}'s {idx.lower()} runway is {length} metres long")
                continue
            if pred == "runwaySurfaceType":
                surface = ", ".join(objs[:-1]) + (" and " + objs[-1] if len(objs) > 1 else objs[0])
                parts.append(f"{subj} has a runway surface of {surface}")
                continue
            # Default: render each object separately
            for o in objs:
                parts.append(_clause(subj, pred, o))
        # Join parts for this subject
        return "; ".join(parts)

    # Build clause strings for each subject
    subject_clauses = [_render_subject(s, pm) for s, pm in grouped.items()]

    # Combine all subject clauses into one sentence
    if not subject_clauses:
        sentence = ""
    elif len(subject_clauses) == 1:
        sentence = subject_clauses[0] + "."
    else:
        sentence = ", ".join(subject_clauses[:-1]) + ", and " + subject_clauses[-1] + "."

    # Capitalise first character
    return sentence[0].upper() + sentence[1:] if sentence else ""

# EVOLVE-BLOCK-END
